((wp)=>{const intervals={low:[20,40,60,90,120,180,240],medium:[40,60,90,120,180,240],high:[60,90,120,180,240]};const vars=typeof window.dfehc_heartbeat_vars==="object"&&window.dfehc_heartbeat_vars?window.dfehc_heartbeat_vars:{};const clampNumber=(v,lo,hi,d)=>{const n=Number(v);if(!Number.isFinite(n))return d;return Math.min(hi,Math.max(lo,n))};const DEFAULT_MIN=20,DEFAULT_MAX=240,ABS_MIN=15,ABS_MAX=300;let MIN=clampNumber(vars.min_interval,ABS_MIN,ABS_MAX,DEFAULT_MIN);let MAX=clampNumber(vars.max_interval,MIN,ABS_MAX,DEFAULT_MAX);if(MIN>MAX){const t=MIN;MIN=MAX;MAX=t}const LOAD_CAP=clampNumber(vars.max_server_load,10,100,85);const msOrAuto=(v,d)=>{const n=Number(v);if(!Number.isFinite(n))return d;return n<=600?n*1000:n};const cacheTimeout=Math.max(15000,msOrAuto(vars.cache_duration,600000));const cacheBypassRate=Math.min(1,Math.max(0,Number(vars.cache_bypass_rate)||0.03));const sanitizeKey=s=>String(s||"").replace(/[^a-z0-9_.-]/gi,"_");const siteKey=sanitizeKey(vars.site_key||location.host);const versionKey=sanitizeKey(vars.ver||"1");const localCacheKey=`dfehc_heartbeat_server_load:${siteKey}:${versionKey}`;const leaderKey=`${localCacheKey}:leader`;const memoryCache=Object.create(null);const SUPPORTS_BC=typeof window.BroadcastChannel==="function";const bc=SUPPORTS_BC?new BroadcastChannel("dfehc-heartbeat"):null;const TAB_ID=Math.random().toString(36).slice(2)+Date.now().toString(36);let isLeader=false,lastLeaderBeat=0;const LEADER_TTL=Math.max(4000,clampNumber(vars.leader_ttl_ms,2000,20000,8000));const LEADER_BEAT=Math.max(1200,clampNumber(vars.leader_beat_ms,800,10000,3000));const jitter=ms=>Math.floor(Math.random()*ms);const safeJsonParse=s=>{try{return JSON.parse(s)}catch{return null}};function readLeader(){let raw=null;try{raw=localStorage.getItem(leaderKey)}catch{}if(!raw)return null;const obj=safeJsonParse(raw);if(!obj||typeof obj!=="object")return null;const ts=Number(obj.ts);const tab=String(obj.tab||"");if(!Number.isFinite(ts)||!tab)return null;return{ts,tab}}function writeLeader(ts,tab){try{localStorage.setItem(leaderKey,JSON.stringify({ts,tab}))}catch{}}function clearLeader(tab){try{const cur=readLeader();if(!cur||cur.tab===tab)localStorage.removeItem(leaderKey)}catch{}}function tryBecomeLeader(){if(document.hidden)return false;const now=Date.now();const cur=readLeader();if(!cur||now-cur.ts>LEADER_TTL){writeLeader(now,TAB_ID);isLeader=true;lastLeaderBeat=now;if(bc)bc.postMessage({t:"leader",ts:now,tab:TAB_ID});return true}if(cur.tab===TAB_ID){isLeader=true;lastLeaderBeat=cur.ts;return true}isLeader=false;return false}function renewLeadership(){if(!isLeader)return;const now=Date.now();if(now-lastLeaderBeat>LEADER_BEAT){writeLeader(now,TAB_ID);lastLeaderBeat=now}}function relinquishLeadership(){if(!isLeader)return;clearLeader(TAB_ID);isLeader=false}const getLocalCache=key=>{try{const raw=localStorage.getItem(key);if(!raw)return null;const parsed=safeJsonParse(raw);if(!parsed||typeof parsed!=="object")return null;const ts=Number(parsed.timestamp);if(!Number.isFinite(ts))return null;const age=Date.now()-ts;if(age<0||age>cacheTimeout)return null;return parsed.data}catch{try{localStorage.removeItem(key)}catch{}return null}};const setLocalCache=(key,data)=>{try{localStorage.setItem(key,JSON.stringify({timestamp:Date.now()-jitter(8000),data}))}catch{}};const nearestFrom=(value,list)=>{if(!Array.isArray(list)||!list.length)return value;let best=list[0],bestD=Math.abs(best-value);for(let i=1;i<list.length;i++){const v=list[i],d=Math.abs(v-value);if(d<bestD){bestD=d;best=v}}return best};const trafficLevel=load=>load<=50?"low":load<=75?"medium":"high";const calcRecommendedIntervalFromLoad=load=>{const bucket=Math.max(0,Math.min(100,Math.round(load)));if(Object.prototype.hasOwnProperty.call(memoryCache,bucket))return memoryCache[bucket];const opts=intervals[trafficLevel(load)]||intervals.low;const min=Math.max(MIN,opts[0]);const max=Math.min(MAX,opts[opts.length-1]);const ratio=Math.max(0,Math.min(1,load/LOAD_CAP));const raw=min+(max-min)*ratio;const clamped=Math.min(Math.max(raw,MIN),MAX);const snapped=nearestFrom(clamped,opts);memoryCache[bucket]=snapped;return snapped};const toNum=v=>{const n=Number(v);return Number.isFinite(n)?n:null};const coerceServerPayload=val=>{if(val&&typeof val==="object"){return{interval:toNum(val.interval),load:toNum(val.load)}}if(Number.isFinite(Number(val))){const n=Number(val);const mode=String(vars.server_payload||"auto").toLowerCase();if(mode==="interval")return{interval:n,load:null};if(mode==="load")return{interval:null,load:n};if(n>=0&&n<=100)return{interval:null,load:n};if(n>100)return{interval:n,load:null}}return{interval:null,load:null}};const debounce=(fn,wait)=>{let t;return(...args)=>{clearTimeout(t);t=setTimeout(()=>fn(...args),wait)}};let lastInterval=null;const applyPresetThenExact=secs=>{const hb=wp&&wp.heartbeat;if(!hb||typeof hb.interval!=="function")return;if(typeof secs!=="number"||!Number.isFinite(secs))return;const rounded=Math.round(secs);if(lastInterval!==null&&Math.round(lastInterval)===rounded)return;const preset=secs<=30?"fast":secs<=90?"standard":"slow";try{hb.interval(preset);hb.interval(secs)}catch{}lastInterval=secs};const setHeartbeatInterval=secs=>{if(!Number.isFinite(secs))return;let s=Math.max(MIN,Math.min(MAX,secs));if(s>=60){s=Math.max(MIN,Math.min(MAX,s+(Math.floor(Math.random()*5)-2)))}applyPresetThenExact(s)};const debouncedSetInterval=debounce(setHeartbeatInterval,200);let failureCount=0,nextRetryAt=0;const backoffMs=()=>Math.min(180000,3000*Math.pow(2,Math.min(failureCount,6)));const fetchWithTimeout=(url,opts,ms)=>{"AbortController"in window?(()=>{const ctrl=new AbortController(),t=setTimeout(()=>ctrl.abort(),ms);return fetch(url,{...opts,signal:ctrl.signal}).finally(()=>clearTimeout(t))})():Promise.race([fetch(url,opts),new Promise((_,rej)=>setTimeout(()=>rej(new Error("timeout")),ms))])};let reqSeq=0;const fallbackPayload=rid=>{const base=Number(vars.fallback_interval)||90;const j=Math.floor(Math.random()*10)-5;return{interval:Math.max(MIN,Math.min(MAX,base+j)),load:null,rid}};const fetchServerData=async(nonce,rid)=>{if(Date.now()<nextRetryAt)return fallbackPayload(rid);if(Math.random()>=cacheBypassRate){const cached=getLocalCache(localCacheKey);if(cached!==null)return{...coerceServerPayload(cached),rid}}const I_AM_LEADER=tryBecomeLeader();if(!I_AM_LEADER){await new Promise(r=>setTimeout(r,Math.min(2000,Math.max(200,200+jitter(600)))));const cached=getLocalCache(localCacheKey);if(cached!==null)return{...coerceServerPayload(cached),rid}}if(navigator.onLine===false)return fallbackPayload(rid);const url=vars.ajax_url||(typeof window.ajaxurl!=="undefined"?window.ajaxurl:`${location.origin.replace(/\/$/,"")}/wp-admin/admin-ajax.php`);try{const body=new URLSearchParams({action:"dfehc_update_heartbeat_interval"});if(nonce)body.append("nonce",nonce);const res=await fetchWithTimeout(url,{method:"POST",body,credentials:"same-origin",headers:{"Content-Type":"application/x-www-form-urlencoded; charset=UTF-8","Cache-Control":"no-store"}},8000);if(!res||!res.ok)throw 0;const json=await res.json();if(!json||json.success!==true)throw 0;setLocalCache(localCacheKey,json.data);if(bc)bc.postMessage({t:"payload",data:json.data});failureCount=0;nextRetryAt=0;renewLeadership();return{...coerceServerPayload(json.data),rid}}catch{failureCount++;nextRetryAt=Date.now()+backoffMs();relinquishLeadership();return fallbackPayload(rid)}};const resolveIntervalFromPayload=payload=>{const interval=payload&&typeof payload.interval==="number"?payload.interval:null;const load=payload&&typeof payload.load==="number"?payload.load:null;const snapList=intervals[trafficLevel(typeof load==="number"?load:LOAD_CAP)]||intervals.low;if(typeof interval==="number"&&Number.isFinite(interval))return nearestFrom(Math.min(Math.max(interval,MIN),MAX),snapList);return calcRecommendedIntervalFromLoad(typeof load==="number"?load:60)};const heartbeat={update:i=>debouncedSetInterval(i),updateUI:i=>{const sel=document.querySelector("#dfehc-heartbeat-interval");if(sel)sel.value=String(i);debouncedSetInterval(i)},init:async nonce=>{const conn=navigator.connection||navigator.mozConnection||navigator.webkitConnection;const et=conn&&conn.effectiveType?String(conn.effectiveType):"";if("deviceMemory"in navigator&&navigator.deviceMemory<2)return;if((conn&&conn.saveData)||et.startsWith("2g")||et.startsWith("slow-2g"))return;const myRid=++reqSeq;const payload=await fetchServerData(nonce,myRid);if(!payload||payload.rid!==reqSeq)return;heartbeat.updateUI(resolveIntervalFromPayload(payload))}};if(bc){bc.onmessage=e=>{const m=e&&e.data?e.data:{};if(m.t==="leader"){const tab=String(m.tab||"");if(tab&&tab!==TAB_ID)isLeader=false}if(m.t==="payload"){setLocalCache(localCacheKey,m.data);Object.keys(memoryCache).forEach(k=>delete memoryCache[k]);debouncedSetInterval(resolveIntervalFromPayload(coerceServerPayload(m.data)))}}}window.addEventListener("storage",e=>{if(!e||e.key!==localCacheKey||!e.newValue)return;const v=safeJsonParse(e.newValue);if(!v||typeof v!=="object"||!("data"in v))return;Object.keys(memoryCache).forEach(k=>delete memoryCache[k]);debouncedSetInterval(resolveIntervalFromPayload(coerceServerPayload(v.data)))});let memoVersion=String(versionKey);function maybeResetMemo(){const v=String(sanitizeKey(vars.ver||"1"));if(v!==memoVersion){memoVersion=v;Object.keys(memoryCache).forEach(k=>delete memoryCache[k])}}function cleanup(){relinquishLeadership();if(bc&&typeof bc.close==="function"){try{bc.close()}catch{}}}document.addEventListener("visibilitychange",()=>{if(!document.hidden)nextRetryAt=0});window.addEventListener("online",()=>{nextRetryAt=0});window.addEventListener("pageshow",e=>{if(e&&e.persisted)nextRetryAt=0});window.addEventListener("pagehide",cleanup,{once:true});window.addEventListener("beforeunload",cleanup,{once:true});document.addEventListener("DOMContentLoaded",()=>{maybeResetMemo();if(String(vars.heartbeat_control_enabled||"")!=="1")return;const nonce=vars.nonce;if("requestIdleCallback"in window){window.requestIdleCallback(()=>heartbeat.init(nonce),{timeout:500})}else{setTimeout(()=>heartbeat.init(nonce),150)}const sel=document.querySelector("#dfehc-heartbeat-interval");if(sel){sel.addEventListener("change",function(){const val=parseInt(String(this.value),10);if(!Number.isNaN(val))heartbeat.update(Math.min(Math.max(val,MIN),MAX))})}})})(window.wp||{});